type DraftMode = "mouse" | "touch"

type TouchCreateState = {
  captureElement: HTMLDivElement
  day: Date
  initialClientX: number
  initialClientY: number
  isActive: boolean
  pointerId: number
  releaseScrollLock: (() => void) | null
  startMinute: number
  timerId: number | null
}

function getClosestTouchPoint(
  touchList: TouchList,
  referenceX: number,
  referenceY: number
) {
  const touches = Array.from(touchList)

  if (touches.length === 0) {
    return null
  }

  return touches.reduce((closestTouch, touch) => {
    const closestDistance = getPointerDistance(
      referenceX,
      referenceY,
      closestTouch.clientX,
      closestTouch.clientY
    )
    const nextDistance = getPointerDistance(
      referenceX,
      referenceY,
      touch.clientX,
      touch.clientY
    )

    return nextDistance < closestDistance ? touch : closestTouch
  })
}

function CalendarTimeGridView(
  props: TimeGridViewProps & TimeGridLiveDragProps
) {
  const [draft, setDraft] = React.useState<CalendarCreateDraft | null>(null)
  const [draftMode, setDraftMode] = React.useState<DraftMode | null>(null)
  const [now, setNow] = React.useState(() => new Date())
  const [activeTouchCreatePointerId, setActiveTouchCreatePointerId] =
    React.useState<number | null>(null)
  const scrollContainerRef = React.useRef<HTMLDivElement | null>(null)
  const touchCreateRef = React.useRef<TouchCreateState | null>(null)
  const minMinute = props.minHour * 60
  const maxMinute = props.maxHour * 60
  const totalMinutes = maxMinute - minMinute
  const slotCount = Math.max(1, totalMinutes / props.slotDuration)
  const gridHeight = slotCount * props.slotHeight
  const {
    focusDayGrid,
    focusedGridDayIndex,
    focusedSlot,
    gridInstructionsId,
    handleGridKeyDown,
    setDayGridRef,
    setFocusedGridDayIndex,
    setFocusedSlot,
  } = useTimeGridNavigation({
    days: props.days,
    maxMinute,
    minMinute,
    onEventCreate: props.onEventCreate,
    slotDuration: props.slotDuration,
  })

  React.useLayoutEffect(() => {
    if (!props.selectedEventId && !props.isPointerDragging) {
      return
    }

    setFocusedGridDayIndex(null)
  }, [props.isPointerDragging, props.selectedEventId, setFocusedGridDayIndex])

  const pragmaticActiveDropTarget = React.useSyncExternalStore(
    (props.activeDropTargetStore ?? nullActiveDropTargetStore).subscribe,
    (props.activeDropTargetStore ?? nullActiveDropTargetStore).getSnapshot,
    (props.activeDropTargetStore ?? nullActiveDropTargetStore).getSnapshot
  )
  const liveActiveDropTarget =
    pragmaticActiveDropTarget ?? props.activeDropTarget ?? null
  const clearDraft = React.useEffectEvent(() => {
    setDraft(null)
    setDraftMode(null)
  })
  const commitDraft = React.useEffectEvent(() => {
    if (!draft) {
      return
    }

    if (!props.onEventCreate) {
      clearDraft()
      return
    }

    const startMinute = Math.min(draft.startMinute, draft.endMinute)
    const endMinute = Math.max(draft.startMinute, draft.endMinute)
    const start = setMinuteOfDay(startOfDay(draft.day), startMinute)
    const end = setMinuteOfDay(
      startOfDay(draft.day),
      Math.min(endMinute + props.slotDuration, 1_440)
    )

    props.onEventCreate({
      start,
      end,
    })
    clearDraft()
  })

  const clearTouchCreateState = React.useCallback(
    (options: { clearDraft?: boolean } = {}) => {
      const touchCreate = touchCreateRef.current

      if (touchCreate?.timerId != null) {
        window.clearTimeout(touchCreate.timerId)
      }

      touchCreate?.releaseScrollLock?.()

      if (touchCreate) {
        try {
          if (
            touchCreate.captureElement.hasPointerCapture(touchCreate.pointerId)
          ) {
            touchCreate.captureElement.releasePointerCapture(
              touchCreate.pointerId
            )
          }
        } catch {
          // Ignore capture teardown errors.
        }
      }

      touchCreateRef.current = null
      setActiveTouchCreatePointerId(null)

      if (options.clearDraft) {
        setDraft(null)
        setDraftMode(null)
      }
    },
    []
  )

  const handleTouchCreatePointerDown = React.useCallback(
    (
      day: Date,
      minuteOfDay: number,
      event: React.PointerEvent<HTMLDivElement>
    ) => {
      if (!props.onEventCreate) {
        return
      }

      clearTouchCreateState({
        clearDraft: true,
      })

      try {
        event.currentTarget.setPointerCapture(event.pointerId)
      } catch {
        // Pointer capture is not guaranteed on every platform.
      }

      const nextTouchCreate: TouchCreateState = {
        captureElement: event.currentTarget,
        day,
        initialClientX: event.clientX,
        initialClientY: event.clientY,
        isActive: false,
        pointerId: event.pointerId,
        releaseScrollLock: null,
        startMinute: minuteOfDay,
        timerId: null,
      }

      nextTouchCreate.timerId = window.setTimeout(() => {
        const activeTouchCreate = touchCreateRef.current

        if (
          !activeTouchCreate ||
          activeTouchCreate.pointerId !== event.pointerId ||
          activeTouchCreate.isActive
        ) {
          return
        }

        activeTouchCreate.isActive = true
        activeTouchCreate.releaseScrollLock = lockDocumentTouchScroll()
        setDraft({
          day: activeTouchCreate.day,
          endMinute: activeTouchCreate.startMinute,
          startMinute: activeTouchCreate.startMinute,
        })
        setDraftMode("touch")
      }, touchLongPressDelay)

      touchCreateRef.current = nextTouchCreate
      setActiveTouchCreatePointerId(event.pointerId)
    },
    [clearTouchCreateState, props.onEventCreate]
  )
  const updateTouchCreateDraftFromPoint = React.useEffectEvent(
    (touchCreate: TouchCreateState, clientX: number, clientY: number) => {
      const target = getTimeGridDropTargetFromPoint(clientX, clientY)

      if (
        !target ||
        target.kind !== "slot" ||
        !isSameDay(target.day, touchCreate.day)
      ) {
        return
      }

      setDraft((currentDraft) => {
        if (
          currentDraft &&
          isSameDay(currentDraft.day, touchCreate.day) &&
          currentDraft.endMinute === target.minuteOfDay
        ) {
          return currentDraft
        }

        return {
          day: touchCreate.day,
          endMinute: target.minuteOfDay,
          startMinute: touchCreate.startMinute,
        }
      })
    }
  )

  React.useEffect(() => {
    if (!draft || draftMode !== "mouse") {
      return
    }

    function handlePointerUp() {
      commitDraft()
    }

    function handlePointerCancel() {
      clearDraft()
    }

    window.addEventListener("pointerup", handlePointerUp)
    window.addEventListener("pointercancel", handlePointerCancel)

    return () => {
      window.removeEventListener("pointerup", handlePointerUp)
      window.removeEventListener("pointercancel", handlePointerCancel)
    }
  }, [draft, draftMode])

  React.useEffect(() => {
    if (activeTouchCreatePointerId == null) {
      return
    }

    const pointerId = activeTouchCreatePointerId

    function handlePointerMove(event: PointerEvent) {
      const touchCreate = touchCreateRef.current

      if (!touchCreate || event.pointerId !== pointerId) {
        return
      }

      if (!touchCreate.isActive) {
        if (
          hasPointerExceededSlop(
            touchCreate.initialClientX,
            touchCreate.initialClientY,
            event.clientX,
            event.clientY
          )
        ) {
          clearTouchCreateState()
        }

        return
      }

      event.preventDefault()
      updateTouchCreateDraftFromPoint(touchCreate, event.clientX, event.clientY)
    }

    function handlePointerUp(event: PointerEvent) {
      const touchCreate = touchCreateRef.current

      if (!touchCreate || event.pointerId !== pointerId) {
        return
      }

      if (!touchCreate.isActive) {
        clearTouchCreateState()
        return
      }

      event.preventDefault()
      commitDraft()
      clearTouchCreateState()
    }

    function handlePointerCancel(event: PointerEvent) {
      const touchCreate = touchCreateRef.current

      if (!touchCreate || event.pointerId !== pointerId) {
        return
      }

      if (touchCreate.isActive) {
        return
      }

      clearTouchCreateState({
        clearDraft: true,
      })
    }

    function handleTouchMove(event: TouchEvent) {
      const touchCreate = touchCreateRef.current

      if (!touchCreate) {
        return
      }

      const touch = getClosestTouchPoint(
        event.touches.length > 0 ? event.touches : event.changedTouches,
        touchCreate.initialClientX,
        touchCreate.initialClientY
      )

      if (!touch) {
        return
      }

      if (!touchCreate.isActive) {
        if (
          hasPointerExceededSlop(
            touchCreate.initialClientX,
            touchCreate.initialClientY,
            touch.clientX,
            touch.clientY
          )
        ) {
          clearTouchCreateState()
        }

        return
      }

      event.preventDefault()
      updateTouchCreateDraftFromPoint(touchCreate, touch.clientX, touch.clientY)
    }

    function handleTouchEnd(event: TouchEvent) {
      const touchCreate = touchCreateRef.current

      if (!touchCreate) {
        return
      }

      if (!touchCreate.isActive) {
        clearTouchCreateState()
        return
      }

      const touch = getClosestTouchPoint(
        event.changedTouches,
        touchCreate.initialClientX,
        touchCreate.initialClientY
      )

      if (touch) {
        updateTouchCreateDraftFromPoint(
          touchCreate,
          touch.clientX,
          touch.clientY
        )
      }

      event.preventDefault()
      commitDraft()
      clearTouchCreateState()
    }

    function handleTouchCancel() {
      if (!touchCreateRef.current) {
        return
      }

      clearTouchCreateState({
        clearDraft: true,
      })
    }

    window.addEventListener("pointermove", handlePointerMove, {
      passive: false,
    })
    window.addEventListener("pointerup", handlePointerUp)
    window.addEventListener("pointercancel", handlePointerCancel)
    window.addEventListener("touchmove", handleTouchMove, {
      passive: false,
    })
    window.addEventListener("touchend", handleTouchEnd, {
      passive: false,
    })
    window.addEventListener("touchcancel", handleTouchCancel)

    return () => {
      window.removeEventListener("pointermove", handlePointerMove)
      window.removeEventListener("pointerup", handlePointerUp)
      window.removeEventListener("pointercancel", handlePointerCancel)
      window.removeEventListener("touchmove", handleTouchMove)
      window.removeEventListener("touchend", handleTouchEnd)
      window.removeEventListener("touchcancel", handleTouchCancel)
    }
  }, [activeTouchCreatePointerId, clearTouchCreateState])

  React.useEffect(() => {
    return () => {
      clearTouchCreateState()
    }
  }, [clearTouchCreateState])

  React.useEffect(() => {
    const intervalId = window.setInterval(() => {
      setNow(new Date())
    }, 30_000)

    return () => {
      window.clearInterval(intervalId)
    }
  }, [])

  React.useEffect(() => {
    const container = scrollContainerRef.current

    if (!container || !props.scrollToTime) {
      return
    }

    const currentDate = new Date()
    const targetMinute =
      props.scrollToTime === "now"
        ? currentDate.getHours() * 60 + currentDate.getMinutes()
        : parseTimeStringToMinuteOfDay(props.scrollToTime)

    if (targetMinute === null) {
      return
    }

    const clampedMinute = Math.min(maxMinute, Math.max(minMinute, targetMinute))
    const nextScrollTop = Math.max(
      0,
      ((clampedMinute - minMinute) / props.slotDuration) * props.slotHeight -
        props.slotHeight * 2
    )

    container.scrollTop = nextScrollTop
  }, [
    maxMinute,
    minMinute,
    props.scrollToTime,
    props.slotDuration,
    props.slotHeight,
  ])

  const allDayEventsByDay = React.useMemo(() => {
    return new Map(
      props.days.map((day) => [
        day.getTime(),
        getAllDayEvents(props.occurrences, day),
      ])
    )
  }, [props.days, props.occurrences])

  const timedLayoutsByDay = React.useMemo(() => {
    return new Map(
      props.days.map((day) => [
        day.getTime(),
        getDayLayout(props.occurrences, day, minMinute, maxMinute),
      ])
    )
  }, [maxMinute, minMinute, props.days, props.occurrences])

  const liveDragPreviewOccurrence = React.useMemo(() => {
    if (!props.activeDrag || !liveActiveDropTarget) {
      return props.dragPreviewOccurrence
    }

    const nextPreviewOccurrence = getPreviewOccurrence(
      props.activeDrag,
      liveActiveDropTarget,
      props.slotDuration,
      props.activeDragOffsetMinutes ?? 0
    )

    if (
      !nextPreviewOccurrence.allDay &&
      props.blockedRanges?.length &&
      intervalOverlapsBlockedRanges(
        nextPreviewOccurrence.start,
        nextPreviewOccurrence.end,
        props.blockedRanges
      )
    ) {
      return undefined
    }

    return nextPreviewOccurrence
  }, [
    liveActiveDropTarget,
    props.activeDrag,
    props.activeDragOffsetMinutes,
    props.blockedRanges,
    props.dragPreviewOccurrence,
    props.slotDuration,
  ])

  const liveDraggingOccurrenceId =
    props.isPointerDragging && props.activeDrag?.kind === "event"
      ? props.activeDrag.occurrence.occurrenceId
      : props.draggingOccurrenceId

  const handleBeginCreate = React.useCallback(
    (day: Date, minuteOfDay: number) => {
      if (!props.onEventCreate) {
        return
      }

      setDraftMode("mouse")
      setDraft({
        day,
        startMinute: minuteOfDay,
        endMinute: minuteOfDay,
      })
    },
    [props.onEventCreate]
  )

  const handleExtendCreate = React.useCallback(
    (day: Date, minuteOfDay: number) => {
      setDraft((currentDraft) => {
        if (!currentDraft || !isSameDay(currentDraft.day, day)) {
          return currentDraft
        }

        if (currentDraft.endMinute === minuteOfDay) {
          return currentDraft
        }

        return {
          ...currentDraft,
          endMinute: minuteOfDay,
        }
      })
    },
    []
  )

  const handleFocusCell = React.useCallback(
    (dayIndex: number, minuteOfDay: number) => {
      setFocusedGridDayIndex(dayIndex)
      setFocusedSlot({
        dayIndex,
        minuteOfDay,
      })
      focusDayGrid(dayIndex)
    },
    [focusDayGrid, setFocusedGridDayIndex, setFocusedSlot]
  )

  const handleBlurDayGrid = React.useCallback(
    (
      dayIndex: number,
      relatedTarget: EventTarget | null,
      currentTarget: EventTarget | null
    ) => {
      if (
        relatedTarget instanceof Node &&
        currentTarget instanceof Node &&
        currentTarget.contains(relatedTarget)
      ) {
        return
      }

      setFocusedGridDayIndex((currentIndex) =>
        currentIndex === dayIndex ? null : currentIndex
      )
    },
    [setFocusedGridDayIndex]
  )

  const handleFocusDayGrid = React.useCallback(
    (dayIndex: number) => {
      setFocusedGridDayIndex(dayIndex)
      setFocusedSlot((currentSlot) => ({
        dayIndex,
        minuteOfDay: clampGridMinute(
          currentSlot.minuteOfDay,
          minMinute,
          maxMinute,
          props.slotDuration
        ),
      }))
    },
    [
      maxMinute,
      minMinute,
      props.slotDuration,
      setFocusedGridDayIndex,
      setFocusedSlot,
    ]
  )

  return (
    <div className="min-h-0 flex-1 overflow-auto" ref={scrollContainerRef}>
      <div className="min-w-4xl">
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            Time
          </div>
          {props.days.map((day) => (
            <div
              key={`header-${day.toISOString()}`}
              className={getCalendarSlotClassName(
                props.classNames,
                "timeGridHeader",
                cn(
                  "border-r border-border/70 last:border-r-0",
                  props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
                )
              )}
              data-calendar-zoom-day={day.toISOString()}
              data-calendar-zoom-surface="header"
              id={getTimeGridHeaderId(day)}
            >
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[11px] tracking-[0.24em] text-muted-foreground uppercase">
                    {formatWeekday(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                  <p className="text-sm font-medium">
                    {formatMonthDayLabel(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                </div>
                {isToday(day) ? (
                  <span className="rounded-full bg-primary/12 px-2 py-1 text-[11px] font-medium text-primary">
                    Today
                  </span>
                ) : null}
              </div>
            </div>
          ))}
        </div>
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            All day
          </div>
          {props.days.map((day) => (
            <MemoizedAllDayDropZone
              key={`all-day-${day.toISOString()}`}
              classNames={props.classNames}
              day={day}
              density={props.density}
              dragPreviewOccurrence={
                liveDragPreviewOccurrence?.allDay &&
                getAllDayEvents([liveDragPreviewOccurrence], day).length > 0
                  ? liveDragPreviewOccurrence
                  : undefined
              }
              draggingOccurrenceId={liveDraggingOccurrenceId}
              events={allDayEventsByDay.get(day.getTime()) ?? []}
              getEventColor={props.getEventColor}
              hourCycle={props.hourCycle}
              isDragTarget={
                liveActiveDropTarget?.kind === "all-day" &&
                liveActiveDropTarget.day.getTime() === day.getTime()
              }
              interactive={props.interactive}
              locale={props.locale}
              onEventDragPointerDown={props.onEventDragPointerDown}
              onEventKeyCommand={props.onEventKeyCommand}
              onOpenContextMenu={props.onOpenContextMenu}
              onSelect={props.onSelectEvent}
              pragmaticDragConfigFactory={props.getPragmaticDragConfig}
              previewOccurrenceId={props.previewOccurrenceId}
              renderEvent={props.renderEvent}
              selectedEventId={props.selectedEventId}
              shouldSuppressEventClick={props.shouldSuppressEventClick}
              timeZone={props.timeZone}
            />
          ))}
        </div>
        <p className="sr-only" id={gridInstructionsId}>
          Use arrow keys to move the active time slot. Use left and right arrows
          to change days.
          {props.onEventCreate
            ? " Press Enter or Space to create an event at the active slot."
            : ""}
        </p>
        <div
          className={getCalendarSlotClassName(
            props.classNames,
            "timeGrid",
            "grid"
          )}
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div className="relative border-r border-border/70">
            {Array.from({ length: slotCount }).map((_, index) => {
              const minute = minMinute + index * props.slotDuration
              const labelDate = setMinuteOfDay(
                startOfDay(props.days[0]),
                minute
              )

              return (
                <div
                  key={`time-label-${minute}`}
                  className="border-b border-border/50 px-3 text-[11px] text-muted-foreground"
                  style={{
                    height: props.slotHeight,
                  }}
                >
                  {minute % 60 === 0 ? (
                    <div className="pt-0.5">
                      <p>
                        {formatHourLabel(labelDate, {
                          hourCycle: props.hourCycle,
                          locale: props.locale,
                          timeZone: props.timeZone,
                        })}
                      </p>
                    </div>
                  ) : null}
                </div>
              )
            })}
          </div>
          {props.days.map((day, dayIndex) => (
            <MemoizedTimeGridDayColumn
              key={`day-column-${day.toISOString()}`}
              activeDropTargetMinuteOfDay={
                liveActiveDropTarget?.kind === "slot" &&
                liveActiveDropTarget.day.getTime() === day.getTime()
                  ? liveActiveDropTarget.minuteOfDay
                  : null
              }
              blockedRanges={props.blockedRanges}
              businessHours={props.businessHours}
              classNames={props.classNames}
              day={day}
              dayIndex={dayIndex}
              dragPreviewOccurrence={
                liveDragPreviewOccurrence &&
                !liveDragPreviewOccurrence.allDay &&
                isSameDay(liveDragPreviewOccurrence.start, day)
                  ? liveDragPreviewOccurrence
                  : undefined
              }
              draggingOccurrenceId={liveDraggingOccurrenceId}
              draft={draft && isSameDay(draft.day, day) ? draft : null}
              focusVisible={focusedGridDayIndex === dayIndex}
              focusedMinuteOfDay={
                focusedSlot.dayIndex === dayIndex
                  ? focusedSlot.minuteOfDay
                  : null
              }
              getEventColor={props.getEventColor}
              gridHeight={gridHeight}
              gridInstructionsId={gridInstructionsId}
              handleBeginCreate={handleBeginCreate}
              handleExtendCreate={handleExtendCreate}
              handleBlurDayGrid={handleBlurDayGrid}
              handleFocusCell={handleFocusCell}
              handleFocusDayGrid={handleFocusDayGrid}
              handleGridKeyDown={handleGridKeyDown}
              handleTouchCreatePointerDown={handleTouchCreatePointerDown}
              hourCycle={props.hourCycle}
              interactive={props.interactive}
              isTodayColumn={isSameDay(day, now)}
              locale={props.locale}
              maxMinute={maxMinute}
              minMinute={minMinute}
              nowIndicatorMinuteOfDay={now.getHours() * 60 + now.getMinutes()}
              onEventDragPointerDown={props.onEventDragPointerDown}
              onEventKeyCommand={props.onEventKeyCommand}
              onOpenContextMenu={props.onOpenContextMenu}
              onResizeHandlePointerDown={props.onResizeHandlePointerDown}
              onSelectEvent={props.onSelectEvent}
              pragmaticDragConfigFactory={props.getPragmaticDragConfig}
              previewOccurrenceId={props.previewOccurrenceId}
              renderEvent={props.renderEvent}
              selectedEventId={props.selectedEventId}
              setDayGridRef={setDayGridRef}
              suppressKeyboardGridFocus={Boolean(
                props.isPointerDragging || props.selectedEventId
              )}
              shouldSuppressEventClick={props.shouldSuppressEventClick}
              showCreatePreviewMeta={Boolean(props.showCreatePreviewMeta)}
              showDragPreviewMeta={Boolean(props.showDragPreviewMeta)}
              slotCount={slotCount}
              slotDuration={props.slotDuration}
              slotHeight={props.slotHeight}
              timeZone={props.timeZone}
              timedLayout={timedLayoutsByDay.get(day.getTime()) ?? []}
              totalMinutes={totalMinutes}
            />
          ))}
        </div>
      </div>
    </div>
  )
}

type TimeGridDayColumnProps = {
  activeDropTargetMinuteOfDay: number | null
  blockedRanges: TimeGridViewProps["blockedRanges"]
  businessHours: TimeGridViewProps["businessHours"]
  classNames?: TimeGridViewProps["classNames"]
  day: Date
  dayIndex: number
  dragPreviewOccurrence?: TimeGridViewProps["dragPreviewOccurrence"]
  draggingOccurrenceId?: string
  draft: CalendarCreateDraft | null
  focusVisible: boolean
  focusedMinuteOfDay: number | null
  getEventColor?: TimeGridViewProps["getEventColor"]
  gridHeight: number
  gridInstructionsId: string
  handleBeginCreate: (day: Date, minuteOfDay: number) => void
  handleExtendCreate: (day: Date, minuteOfDay: number) => void
  handleBlurDayGrid: (
    dayIndex: number,
    relatedTarget: EventTarget | null,
    currentTarget: EventTarget | null
  ) => void
  handleFocusCell: (dayIndex: number, minuteOfDay: number) => void
  handleFocusDayGrid: (dayIndex: number) => void
  handleGridKeyDown: (
    dayIndex: number,
    day: Date,
    event: React.KeyboardEvent<HTMLDivElement>
  ) => void
  handleTouchCreatePointerDown?: (
    day: Date,
    minuteOfDay: number,
    event: React.PointerEvent<HTMLDivElement>
  ) => void
  hourCycle?: 12 | 24
  interactive: boolean
  isTodayColumn: boolean
  locale?: string
  maxMinute: number
  minMinute: number
  nowIndicatorMinuteOfDay: number
  onEventDragPointerDown?: TimeGridViewProps["onEventDragPointerDown"]
  onEventKeyCommand: TimeGridViewProps["onEventKeyCommand"]
  onOpenContextMenu?: TimeGridViewProps["onOpenContextMenu"]
  onResizeHandlePointerDown?: TimeGridViewProps["onResizeHandlePointerDown"]
  onSelectEvent: TimeGridViewProps["onSelectEvent"]
  pragmaticDragConfigFactory?: TimeGridLiveDragProps["getPragmaticDragConfig"]
  previewOccurrenceId?: string
  renderEvent?: TimeGridViewProps["renderEvent"]
  selectedEventId?: string
  setDayGridRef: (dayIndex: number, element: HTMLDivElement | null) => void
  suppressKeyboardGridFocus: boolean
  shouldSuppressEventClick?: TimeGridViewProps["shouldSuppressEventClick"]
  showCreatePreviewMeta: boolean
  showDragPreviewMeta: boolean
  slotCount: number
  slotDuration: number
  slotHeight: number
  timeZone?: string
  timedLayout: ReturnType<typeof getDayLayout>
  totalMinutes: number
}

const MemoizedTimeGridDayColumn = React.memo(
  function TimeGridDayColumn({
    activeDropTargetMinuteOfDay,
    blockedRanges,
    businessHours,
    classNames,
    day,
    dayIndex,
    dragPreviewOccurrence,
    draggingOccurrenceId,
    draft,
    focusVisible,
    focusedMinuteOfDay,
    getEventColor,
    gridHeight,
    gridInstructionsId,
    handleBeginCreate,
    handleExtendCreate,
    handleBlurDayGrid,
    handleFocusCell,
    handleFocusDayGrid,
    handleGridKeyDown,
    handleTouchCreatePointerDown,
    hourCycle,
    interactive,
    isTodayColumn,
    locale,
    maxMinute,
    minMinute,
    nowIndicatorMinuteOfDay,
    onEventDragPointerDown,
    onEventKeyCommand,
    onOpenContextMenu,
    onResizeHandlePointerDown,
    onSelectEvent,
    pragmaticDragConfigFactory,
    previewOccurrenceId,
    renderEvent,
    selectedEventId,
    setDayGridRef,
    suppressKeyboardGridFocus,
    shouldSuppressEventClick,
    showCreatePreviewMeta,
    showDragPreviewMeta,
    slotCount,
    slotDuration,
    slotHeight,
    timeZone,
    timedLayout,
    totalMinutes,
  }: TimeGridDayColumnProps) {
    const previewLayout = getTimeGridPreviewLayout(
      timedLayout,
      dragPreviewOccurrence,
      day,
      minMinute,
      maxMinute
    )
    const showFocusedGridCell = !suppressKeyboardGridFocus
    const showTimedSlotDropHighlight = !previewLayout
    const showNowIndicator =
      isTodayColumn &&
      nowIndicatorMinuteOfDay >= minMinute &&
      nowIndicatorMinuteOfDay <= maxMinute
    const nowIndicatorTop =
      ((nowIndicatorMinuteOfDay - minMinute) / totalMinutes) * gridHeight
    const headerId = getTimeGridHeaderId(day)
    const activeSlotId =
      focusedMinuteOfDay != null
        ? getTimeGridSlotId(day, focusedMinuteOfDay)
        : undefined
    const slotDescriptors = React.useMemo(() => {
      return Array.from({ length: slotCount }, (_, index) => {
        const minuteOfDay = minMinute + index * slotDuration
        const slotStart = setMinuteOfDay(startOfDay(day), minuteOfDay)
        const slotEnd = setMinuteOfDay(
          startOfDay(day),
          Math.min(minuteOfDay + slotDuration, 1_440)
        )

        return {
          blocked:
            blockedRanges?.some(
              (range) =>
                slotStart.getTime() < range.end.getTime() &&
                slotEnd.getTime() > range.start.getTime()
            ) ?? false,
          minuteOfDay,
          slotId: getTimeGridSlotId(day, minuteOfDay),
        }
      })
    }, [blockedRanges, day, minMinute, slotCount, slotDuration])
    const draftPreviewLabels = React.useMemo(() => {
      if (!draft) {
        return null
      }

      const startMinute = Math.min(draft.startMinute, draft.endMinute)
      const endMinute = Math.max(draft.startMinute, draft.endMinute)
      const start = setMinuteOfDay(startOfDay(day), startMinute)
      const end = setMinuteOfDay(
        startOfDay(day),
        Math.min(endMinute + slotDuration, 1_440)
      )

      return {
        durationLabel: formatDurationLabel(start, end),
        timeLabel: formatEventTimeLabel(start, end, {
          hourCycle,
          locale,
          timeZone,
        }),
      }
    }, [day, draft, hourCycle, locale, slotDuration, timeZone])

    return (
      <div
        className={getCalendarSlotClassName(
          classNames,
          "timeGridDayColumn",
          "relative border-r border-border/70 last:border-r-0"
        )}
        data-calendar-zoom-day={day.toISOString()}
        data-calendar-zoom-surface="column"
      >
        <div
          aria-activedescendant={showFocusedGridCell ? activeSlotId : undefined}
          aria-colcount={1}
          aria-describedby={gridInstructionsId}
          aria-labelledby={headerId}
          aria-rowcount={slotCount}
          className="relative h-full outline-none focus-visible:ring-2 focus-visible:ring-primary/35 focus-visible:ring-inset"
          onBlur={(event) =>
            handleBlurDayGrid(
              dayIndex,
              event.relatedTarget,
              event.currentTarget
            )
          }
          onFocus={() => {
            handleFocusDayGrid(dayIndex)
          }}
          onKeyDown={(event) => handleGridKeyDown(dayIndex, day, event)}
          ref={(element) => {
            setDayGridRef(dayIndex, element)
          }}
          role="grid"
          style={{
            height: gridHeight,
          }}
          tabIndex={showFocusedGridCell && focusedMinuteOfDay != null ? 0 : -1}
        >
          <TimeGridBackground
            blockedRanges={blockedRanges}
            businessHours={businessHours}
            day={day}
            gridHeight={gridHeight}
            maxMinute={maxMinute}
            minMinute={minMinute}
            slotDuration={slotDuration}
            slotHeight={slotHeight}
          />
          <div
            className="absolute inset-0 grid"
            style={{
              gridTemplateRows: `repeat(${slotCount}, ${slotHeight}px)`,
            }}
          >
            {slotDescriptors.map(({ blocked, minuteOfDay, slotId }) => {
              return (
                <div key={`${day.toISOString()}-${minuteOfDay}`} role="row">
                  <MemoizedTimeSlotDropZone
                    active={
                      showFocusedGridCell &&
                      focusedMinuteOfDay === minuteOfDay &&
                      !draft
                    }
                    blocked={blocked}
                    classNames={classNames}
                    day={day}
                    dayIndex={dayIndex}
                    focusVisible={showFocusedGridCell && focusVisible}
                    hourCycle={hourCycle}
                    isDragTarget={
                      showTimedSlotDropHighlight &&
                      activeDropTargetMinuteOfDay === minuteOfDay
                    }
                    isDraftDay={Boolean(draft)}
                    locale={locale}
                    minuteOfDay={minuteOfDay}
                    onBeginCreate={handleBeginCreate}
                    onExtendCreate={handleExtendCreate}
                    onFocusCell={handleFocusCell}
                    onTouchCreatePointerDown={handleTouchCreatePointerDown}
                    slotId={slotId}
                    timeZone={timeZone}
                  />
                </div>
              )
            })}
          </div>
          {draft ? (
            <div
              className="pointer-events-none absolute inset-x-1 overflow-hidden rounded-[min(var(--radius-sm),4px)] border border-dashed border-primary/55 bg-primary/10 shadow-xs"
              style={{
                top:
                  ((Math.min(draft.startMinute, draft.endMinute) - minMinute) /
                    slotDuration) *
                  slotHeight,
                height:
                  ((Math.abs(draft.endMinute - draft.startMinute) +
                    slotDuration) /
                    slotDuration) *
                  slotHeight,
              }}
            >
              <span
                aria-hidden
                className="pointer-events-none absolute top-1.5 bottom-1.5 left-1 w-0.5 rounded-full bg-primary/80"
              />
              {showCreatePreviewMeta ? (
                <div className="absolute top-2 right-2 left-3 min-w-0 rounded-[min(var(--radius-sm),4px)] bg-background/95 px-2 py-1 shadow-xs">
                  <p className="truncate text-[10px] font-medium tracking-[0.18em] text-muted-foreground uppercase">
                    {draftPreviewLabels?.timeLabel}
                  </p>
                  <p className="truncate text-[11px] leading-tight font-medium text-foreground">
                    {draftPreviewLabels?.durationLabel}
                  </p>
                </div>
              ) : null}
            </div>
          ) : null}
          {previewLayout ? (
            <TimeGridPreviewLayer
              column={previewLayout.column}
              columns={previewLayout.columns}
              height={previewLayout.height}
              minMinute={minMinute}
              slotDuration={slotDuration}
              slotHeight={slotHeight}
              top={previewLayout.top}
            />
          ) : null}
          {showNowIndicator ? (
            <div
              className="pointer-events-none absolute inset-x-0 z-20"
              style={{
                top: nowIndicatorTop,
              }}
            >
              <div className="relative h-0">
                <div className="absolute top-1/2 left-0 size-2.5 -translate-x-1/2 -translate-y-1/2 rounded-full bg-primary shadow-[0_0_0_3px_var(--color-background)]" />
                <div className="h-0.5 w-full bg-primary" />
              </div>
            </div>
          ) : null}
          {timedLayout.map((item, index) => {
            const width = 100 / item.columns
            const left = item.column * width

            return (
              <div
                key={item.occurrence.occurrenceId}
                className="absolute px-1"
                style={{
                  top: ((item.top - minMinute) / slotDuration) * slotHeight,
                  height: Math.max(
                    slotHeight - 4,
                    (item.height / slotDuration) * slotHeight
                  ),
                  left: `calc(${left}% + 0px)`,
                  width: `calc(${width}% - 0px)`,
                }}
              >
                <CalendarEventCard
                  accentColor={getResolvedAccentColor(
                    item.occurrence,
                    getEventColor,
                    index
                  )}
                  classNames={classNames}
                  density="comfortable"
                  dragging={
                    previewOccurrenceId === item.occurrence.occurrenceId
                      ? false
                      : draggingOccurrenceId === item.occurrence.occurrenceId
                  }
                  event={item.occurrence}
                  interactive={interactive}
                  onDragPointerDown={onEventDragPointerDown}
                  onEventKeyCommand={onEventKeyCommand}
                  onOpenContextMenu={onOpenContextMenu}
                  onResizeHandlePointerDown={onResizeHandlePointerDown}
                  onSelect={onSelectEvent}
                  pragmaticDragConfigFactory={pragmaticDragConfigFactory}
                  preview={previewOccurrenceId === item.occurrence.occurrenceId}
                  previewMetaLabel={
                    showDragPreviewMeta &&
                    previewOccurrenceId === item.occurrence.occurrenceId
                      ? formatDurationLabel(
                          item.occurrence.start,
                          item.occurrence.end,
                          item.occurrence.allDay
                        )
                      : undefined
                  }
                  renderEvent={renderEvent}
                  selected={selectedEventId === item.occurrence.occurrenceId}
                  shouldSuppressClick={shouldSuppressEventClick}
                  showResizeHandles
                  timeLabel={getEventMetaLabel(item.occurrence, {
                    hourCycle,
                    locale,
                    timeZone,
                  })}
                  variant="time-grid"
                />
              </div>
            )
          })}
        </div>
      </div>
    )
  },
  (previousProps, nextProps) => {
    return (
      previousProps.activeDropTargetMinuteOfDay ===
        nextProps.activeDropTargetMinuteOfDay &&
      previousProps.blockedRanges === nextProps.blockedRanges &&
      previousProps.businessHours === nextProps.businessHours &&
      previousProps.classNames === nextProps.classNames &&
      previousProps.day.getTime() === nextProps.day.getTime() &&
      previousProps.dayIndex === nextProps.dayIndex &&
      previousProps.dragPreviewOccurrence === nextProps.dragPreviewOccurrence &&
      previousProps.draggingOccurrenceId === nextProps.draggingOccurrenceId &&
      previousProps.draft === nextProps.draft &&
      previousProps.focusVisible === nextProps.focusVisible &&
      previousProps.focusedMinuteOfDay === nextProps.focusedMinuteOfDay &&
      previousProps.getEventColor === nextProps.getEventColor &&
      previousProps.gridHeight === nextProps.gridHeight &&
      previousProps.gridInstructionsId === nextProps.gridInstructionsId &&
      previousProps.handleBeginCreate === nextProps.handleBeginCreate &&
      previousProps.handleExtendCreate === nextProps.handleExtendCreate &&
      previousProps.handleBlurDayGrid === nextProps.handleBlurDayGrid &&
      previousProps.handleFocusCell === nextProps.handleFocusCell &&
      previousProps.handleFocusDayGrid === nextProps.handleFocusDayGrid &&
      previousProps.handleGridKeyDown === nextProps.handleGridKeyDown &&
      previousProps.handleTouchCreatePointerDown ===
        nextProps.handleTouchCreatePointerDown &&
      previousProps.hourCycle === nextProps.hourCycle &&
      previousProps.interactive === nextProps.interactive &&
      previousProps.isTodayColumn === nextProps.isTodayColumn &&
      previousProps.locale === nextProps.locale &&
      previousProps.maxMinute === nextProps.maxMinute &&
      previousProps.minMinute === nextProps.minMinute &&
      previousProps.nowIndicatorMinuteOfDay ===
        nextProps.nowIndicatorMinuteOfDay &&
      previousProps.onEventDragPointerDown ===
        nextProps.onEventDragPointerDown &&
      previousProps.onEventKeyCommand === nextProps.onEventKeyCommand &&
      previousProps.onOpenContextMenu === nextProps.onOpenContextMenu &&
      previousProps.onResizeHandlePointerDown ===
        nextProps.onResizeHandlePointerDown &&
      previousProps.onSelectEvent === nextProps.onSelectEvent &&
      previousProps.pragmaticDragConfigFactory ===
        nextProps.pragmaticDragConfigFactory &&
      previousProps.previewOccurrenceId === nextProps.previewOccurrenceId &&
      previousProps.renderEvent === nextProps.renderEvent &&
      previousProps.selectedEventId === nextProps.selectedEventId &&
      previousProps.setDayGridRef === nextProps.setDayGridRef &&
      previousProps.suppressKeyboardGridFocus ===
        nextProps.suppressKeyboardGridFocus &&
      previousProps.shouldSuppressEventClick ===
        nextProps.shouldSuppressEventClick &&
      previousProps.showCreatePreviewMeta === nextProps.showCreatePreviewMeta &&
      previousProps.showDragPreviewMeta === nextProps.showDragPreviewMeta &&
      previousProps.slotCount === nextProps.slotCount &&
      previousProps.slotDuration === nextProps.slotDuration &&
      previousProps.slotHeight === nextProps.slotHeight &&
      previousProps.timeZone === nextProps.timeZone &&
      previousProps.timedLayout === nextProps.timedLayout &&
      previousProps.totalMinutes === nextProps.totalMinutes
    )
  }
)

import * as React from "react"

const focusableSelector = [
  "a[href]",
  "area[href]",
  "button:not([disabled])",
  "input:not([disabled]):not([type='hidden'])",
  "select:not([disabled])",
  "textarea:not([disabled])",
  "[contenteditable='true']",
  "[tabindex]:not([tabindex='-1'])",
].join(",")

type UseModalFocusOptions = {
  containerRef: React.RefObject<HTMLElement | null>
  initialFocusRef?: React.RefObject<HTMLElement | null>
  onClose: () => void
  open: boolean
}

export function useModalFocus({
  containerRef,
  initialFocusRef,
  onClose,
  open,
}: UseModalFocusOptions) {
  React.useEffect(() => {
    if (!open) {
      return
    }

    const focusTrapContainer = containerRef.current

    if (!(focusTrapContainer instanceof HTMLElement)) {
      return
    }

    const container = focusTrapContainer

    const previousFocusedElement =
      document.activeElement instanceof HTMLElement
        ? document.activeElement
        : null
    const previousBodyOverflow = document.body.style.overflow

    document.body.style.overflow = "hidden"

    const frameId = requestAnimationFrame(() => {
      const nextFocusTarget =
        initialFocusRef?.current ?? getFocusableElements(container)[0] ?? container

      nextFocusTarget.focus()
    })

    function handleKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.preventDefault()
        onClose()
        return
      }

      if (event.key !== "Tab") {
        return
      }

      const focusableElements = getFocusableElements(container)

      if (focusableElements.length === 0) {
        event.preventDefault()
        container.focus()
        return
      }

      const firstElement = focusableElements[0]
      const lastElement = focusableElements[focusableElements.length - 1]
      const activeElement =
        document.activeElement instanceof Node ? document.activeElement : null

      if (event.shiftKey) {
        if (activeElement === firstElement || !container.contains(activeElement)) {
          event.preventDefault()
          lastElement.focus()
        }

        return
      }

      if (activeElement === lastElement || !container.contains(activeElement)) {
        event.preventDefault()
        firstElement.focus()
      }
    }

    document.addEventListener("keydown", handleKeyDown)

    return () => {
      cancelAnimationFrame(frameId)
      document.removeEventListener("keydown", handleKeyDown)
      document.body.style.overflow = previousBodyOverflow
      previousFocusedElement?.focus()
    }
  }, [containerRef, initialFocusRef, onClose, open])
}

function getFocusableElements(container: HTMLElement) {
  return Array.from(
    container.querySelectorAll<HTMLElement>(focusableSelector)
  ).filter((element) => {
    const computedStyle = window.getComputedStyle(element)

    return (
      !element.hasAttribute("disabled") &&
      computedStyle.display !== "none" &&
      computedStyle.visibility !== "hidden"
    )
  })
}

import type { CSSProperties } from "react"

import { addDays, addMinutes, startOfDay } from "date-fns"

import type {
  CalendarDragData,
  CalendarDropTarget,
  CalendarEventVariant,
  CalendarMoveOperation,
  CalendarOccurrence,
  CalendarResizeOperation,
  CalendarSurfaceShadow,
} from "../../../types"
import {
  clampResize,
  copyTimeParts,
  getDaySpan,
  setMinuteOfDay,
} from "../../../utils"

export const dragActivationDistance = 6
export const touchLongPressDelay = 320
export const touchGestureMoveSlop = 10

let activeTouchScrollLocks = 0
let previousTouchScrollStyles: {
  bodyOverflow: string
  bodyOverscrollBehavior: string
  bodyTouchAction: string
  documentOverscrollBehavior: string
  documentTouchAction: string
} | null = null

export type ActiveDragInteraction = {
  captureElement: HTMLElement | null
  currentClientX: number
  currentClientY: number
  hasPointerCapture: boolean
  initialClientX: number
  initialClientY: number
  isDragging: boolean
  pointerId: number
  pointerType: string
}

export type DragOverlayPosition = {
  clientX: number
  clientY: number
}

export type ActiveResizeState = {
  captureElement: HTMLElement | null
  edge: "start" | "end"
  hasPointerCapture: boolean
  occurrence: CalendarOccurrence
  pointerId: number
  pointerType: string
  variant: CalendarEventVariant
}

export function getCalendarSurfaceShadowClassName(
  surfaceShadow: CalendarSurfaceShadow
) {
  if (surfaceShadow === "sm") {
    return "shadow-[0_12px_36px_-24px_rgba(15,23,42,0.28)]"
  }

  if (surfaceShadow === "md") {
    return "shadow-[0_20px_80px_-48px_rgba(15,23,42,0.55)]"
  }

  return undefined
}

export function getPreviewOccurrence(
  activeDrag: CalendarDragData,
  target: CalendarDropTarget,
  slotDuration: number,
  dragOffsetMinutes = 0
) {
  if (activeDrag.kind === "event") {
    const operation = getMoveOperation(
      activeDrag.occurrence,
      target,
      activeDrag.variant === "time-grid" ? dragOffsetMinutes : 0,
      slotDuration
    )

    return {
      ...activeDrag.occurrence,
      start: operation.nextStart,
      end: operation.nextEnd,
      allDay: operation.allDay ?? activeDrag.occurrence.allDay,
    }
  }

  const operation = getResizeOperation(
    activeDrag.occurrence,
    activeDrag.edge,
    target,
    slotDuration
  )

  return {
    ...activeDrag.occurrence,
    start: operation.nextStart,
    end: operation.nextEnd,
  }
}

export function getMoveOperation(
  occurrence: CalendarOccurrence,
  target: CalendarDropTarget,
  dragOffsetMinutes = 0,
  slotDuration = 30
): CalendarMoveOperation {
  const durationMs = occurrence.end.getTime() - occurrence.start.getTime()
  let nextStart: Date
  let nextEnd: Date
  let allDay = occurrence.allDay

  if (target.kind === "slot") {
    const durationMinutes = Math.max(1, Math.round(durationMs / 60_000))
    const latestStartMinute = Math.max(
      0,
      1_440 - Math.min(durationMinutes, 1_440)
    )
    const rawStartMinute = Math.min(
      latestStartMinute,
      Math.max(0, target.minuteOfDay - dragOffsetMinutes)
    )
    const nextStartMinute = Math.min(
      latestStartMinute,
      Math.max(0, snapMinuteToGrid(rawStartMinute, slotDuration))
    )

    nextStart = setMinuteOfDay(startOfDay(target.day), nextStartMinute)
    nextEnd = new Date(nextStart.getTime() + durationMs)
    allDay = false
  } else {
    allDay = target.kind === "all-day" || occurrence.allDay

    if (allDay) {
      nextStart = startOfDay(target.day)
      nextEnd = addDays(nextStart, getDaySpan(occurrence))
    } else {
      nextStart = copyTimeParts(startOfDay(target.day), occurrence.start)
      nextEnd = new Date(nextStart.getTime() + durationMs)
    }
  }

  return {
    occurrence,
    nextStart,
    nextEnd,
    previousStart: occurrence.start,
    previousEnd: occurrence.end,
    allDay,
  }
}

function snapMinuteToGrid(minuteOfDay: number, slotDuration: number) {
  if (slotDuration <= 1) {
    return minuteOfDay
  }

  return Math.round(minuteOfDay / slotDuration) * slotDuration
}

export function getDragOffsetMinutes(
  dragData: CalendarDragData,
  dragRect: DOMRect | null,
  clientY: number
) {
  if (
    dragData.kind !== "event" ||
    dragData.variant !== "time-grid" ||
    dragData.occurrence.allDay ||
    !dragRect ||
    dragRect.height <= 0
  ) {
    return 0
  }

  const durationMinutes = Math.max(
    1,
    Math.round(
      (dragData.occurrence.end.getTime() -
        dragData.occurrence.start.getTime()) /
        60_000
    )
  )
  const pointerOffsetY = Math.min(
    dragRect.height,
    Math.max(0, clientY - dragRect.top)
  )

  return Math.min(
    Math.max(0, durationMinutes - 1),
    Math.round((pointerOffsetY / dragRect.height) * durationMinutes)
  )
}

export function getResizeOperation(
  occurrence: CalendarOccurrence,
  edge: "start" | "end",
  target: CalendarDropTarget,
  slotDuration: number
): CalendarResizeOperation {
  const rawDate =
    target.kind === "slot"
      ? setMinuteOfDay(startOfDay(target.day), target.minuteOfDay)
      : startOfDay(target.day)

  if (edge === "start") {
    return {
      occurrence,
      edge,
      nextStart: clampResize(rawDate, occurrence.end, "start", slotDuration),
      nextEnd: occurrence.end,
      previousStart: occurrence.start,
      previousEnd: occurrence.end,
    }
  }

  const adjustedEnd =
    target.kind === "slot"
      ? addMinutes(rawDate, slotDuration)
      : addDays(rawDate, 1)

  return {
    occurrence,
    edge,
    nextStart: occurrence.start,
    nextEnd: clampResize(adjustedEnd, occurrence.start, "end", slotDuration),
    previousStart: occurrence.start,
    previousEnd: occurrence.end,
  }
}

export function areDropTargetsEqual(
  left: CalendarDropTarget | null,
  right: CalendarDropTarget | null
) {
  if (left === right) {
    return true
  }

  if (!left || !right || left.kind !== right.kind) {
    return false
  }

  if (left.day.getTime() !== right.day.getTime()) {
    return false
  }

  if (left.resourceId !== right.resourceId) {
    return false
  }

  if (left.kind === "slot" && right.kind === "slot") {
    return left.minuteOfDay === right.minuteOfDay
  }

  return true
}

export function getPointerDistance(
  startClientX: number,
  startClientY: number,
  currentClientX: number,
  currentClientY: number
) {
  return Math.hypot(
    currentClientX - startClientX,
    currentClientY - startClientY
  )
}

export function isTouchPointer(pointerType: string | null | undefined) {
  return pointerType === "touch"
}

export function hasPointerExceededSlop(
  startClientX: number,
  startClientY: number,
  currentClientX: number,
  currentClientY: number,
  slop = touchGestureMoveSlop
) {
  return (
    getPointerDistance(
      startClientX,
      startClientY,
      currentClientX,
      currentClientY
    ) > slop
  )
}

export function lockDocumentTouchScroll() {
  if (typeof document === "undefined" || !document.body) {
    return () => {}
  }

  const documentElement = document.documentElement
  const body = document.body

  if (activeTouchScrollLocks === 0) {
    previousTouchScrollStyles = {
      bodyOverflow: body.style.overflow,
      bodyOverscrollBehavior: body.style.overscrollBehavior,
      bodyTouchAction: body.style.touchAction,
      documentOverscrollBehavior: documentElement.style.overscrollBehavior,
      documentTouchAction: documentElement.style.touchAction,
    }
    documentElement.style.overscrollBehavior = "none"
    documentElement.style.touchAction = "none"
    body.style.overflow = "hidden"
    body.style.overscrollBehavior = "none"
    body.style.touchAction = "none"
  }

  activeTouchScrollLocks += 1

  let released = false

  return () => {
    if (released) {
      return
    }

    released = true
    activeTouchScrollLocks = Math.max(0, activeTouchScrollLocks - 1)

    if (activeTouchScrollLocks > 0 || !previousTouchScrollStyles) {
      return
    }

    documentElement.style.overscrollBehavior =
      previousTouchScrollStyles.documentOverscrollBehavior
    documentElement.style.touchAction =
      previousTouchScrollStyles.documentTouchAction
    body.style.overflow = previousTouchScrollStyles.bodyOverflow
    body.style.overscrollBehavior =
      previousTouchScrollStyles.bodyOverscrollBehavior
    body.style.touchAction = previousTouchScrollStyles.bodyTouchAction
    previousTouchScrollStyles = null
  }
}

export function getDragOverlayStyle(
  dragRect: DOMRect | null,
  interaction: ActiveDragInteraction | null,
  position: DragOverlayPosition | null
): CSSProperties | undefined {
  if (!dragRect || !interaction || !position) {
    return undefined
  }

  return {
    height: dragRect.height,
    left: dragRect.left + position.clientX - interaction.initialClientX,
    position: "fixed",
    top: dragRect.top + position.clientY - interaction.initialClientY,
    width: dragRect.width,
  }
}

export function getDragSurfaceRect(target: EventTarget | null): DOMRect | null {
  if (!(target instanceof Element)) {
    return null
  }

  return (
    target
      .closest<HTMLElement>("[data-calendar-drag-surface]")
      ?.getBoundingClientRect() ?? null
  )
}

export function getCalendarDropTargetFromPoint(
  clientX: number,
  clientY: number
): CalendarDropTarget | null {
  if (typeof document === "undefined") {
    return null
  }

  const match =
    document
      .elementsFromPoint(clientX, clientY)
      .find((element): element is HTMLElement => {
        return (
          element instanceof HTMLElement &&
          !!element.dataset.calendarDropTargetKind
        )
      }) ?? getFallbackCalendarDropTargetElement(clientX, clientY)

  if (!match) {
    return null
  }

  return parseCalendarDropTargetElement(match)
}

function getFallbackCalendarDropTargetElement(
  clientX: number,
  clientY: number
): HTMLElement | null {
  const matches = Array.from(
    document.querySelectorAll<HTMLElement>("[data-calendar-drop-target-kind]")
  ).filter((element) => {
    const rect = element.getBoundingClientRect()

    return (
      clientX >= rect.left &&
      clientX <= rect.right &&
      clientY >= rect.top &&
      clientY <= rect.bottom
    )
  })

  if (matches.length === 0) {
    return null
  }

  matches.sort((left, right) => {
    const leftRect = left.getBoundingClientRect()
    const rightRect = right.getBoundingClientRect()
    const leftArea = leftRect.width * leftRect.height
    const rightArea = rightRect.width * rightRect.height

    return leftArea - rightArea
  })

  return matches[0] ?? null
}

function parseCalendarDropTargetElement(
  match: HTMLElement
): CalendarDropTarget | null {
  const kind = match.dataset.calendarDropTargetKind
  const dayValue = match.dataset.calendarDropTargetDay
  const resourceId =
    match.dataset.calendarDropTargetResourceId?.trim() || undefined

  if (!kind || !dayValue) {
    return null
  }

  const day = new Date(dayValue)

  if (Number.isNaN(day.getTime())) {
    return null
  }

  if (kind === "slot") {
    const minuteValue = match.dataset.calendarDropTargetMinute
    const minuteOfDay = Number(minuteValue)

    if (minuteValue === undefined || !Number.isFinite(minuteOfDay)) {
      return null
    }

    return {
      kind,
      day,
      minuteOfDay,
      resourceId,
    }
  }

  if (kind === "day" || kind === "all-day") {
    return {
      kind,
      day,
      resourceId,
    }
  }

  return null
}

export function getTimeGridDropTargetFromPoint(
  clientX: number,
  clientY: number
): CalendarDropTarget | null {
  const target = getCalendarDropTargetFromPoint(clientX, clientY)

  return target?.kind === "slot" ? target : null
}

export function getResizeDropTargetFromPoint(
  _variant: CalendarEventVariant,
  clientX: number,
  clientY: number
): CalendarDropTarget | null {
  return getTimeGridDropTargetFromPoint(clientX, clientY)
}

import * as React from "react"

import { addDays, addMinutes } from "date-fns"

import type {
  CalendarCreateOperation,
  CalendarEvent,
  CalendarEventMenuPosition,
  CalendarMoveOperation,
  CalendarOccurrence,
  CalendarResizeOperation,
} from "../../../types"
import {
  applyMoveOperation,
  applyResizeOperation,
  canMoveOccurrence,
  canResizeOccurrence,
  clampResize,
  formatEventTimeLabel,
} from "../../../utils"

import { getMoveOperation, getResizeOperation } from "./root-utils"

type UseCalendarCoreActionsOptions = {
  hourCycle?: 12 | 24
  locale?: string
  onEventContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onEventCreate?: (operation: CalendarCreateOperation) => void
  onEventCreateRequest?: (operation: CalendarCreateOperation) => void
  onEventMove?: (operation: CalendarMoveOperation) => void
  onEventMoveRequest?: (operation: CalendarMoveOperation) => void
  onEventResize?: (operation: CalendarResizeOperation) => void
  onEventResizeRequest?: (operation: CalendarResizeOperation) => void
  onEventSelect?: (occurrence: CalendarOccurrence) => void
  onSelectedEventChange?: (id?: string) => void
  setOptimisticEvents: React.Dispatch<React.SetStateAction<CalendarEvent[]>>
  shouldBlockTimedRange: (
    start: Date,
    end: Date,
    allDay: boolean | undefined
  ) => boolean
  slotDuration: number
  timeZone?: string
}

export function useCalendarCoreActions({
  hourCycle,
  locale,
  onEventContextMenu,
  onEventCreate,
  onEventCreateRequest,
  onEventMove,
  onEventMoveRequest,
  onEventResize,
  onEventResizeRequest,
  onEventSelect,
  onSelectedEventChange,
  setOptimisticEvents,
  shouldBlockTimedRange,
  slotDuration,
  timeZone,
}: UseCalendarCoreActionsOptions) {
  const [liveAnnouncement, setLiveAnnouncement] = React.useState("")

  const announce = React.useCallback((message: string) => {
    setLiveAnnouncement(message)
  }, [])

  function formatAnnouncementRange(
    start: Date,
    end: Date,
    allDay: boolean | undefined
  ) {
    return formatEventTimeLabel(start, end, {
      allDay,
      hourCycle,
      locale,
      timeZone,
    })
  }

  function handleSelectEvent(occurrence: CalendarOccurrence) {
    onSelectedEventChange?.(occurrence.occurrenceId)
    onEventSelect?.(occurrence)
  }

  function commitCreateEvent(operation: CalendarCreateOperation) {
    if (!onEventCreate) {
      return
    }

    if (
      shouldBlockTimedRange(operation.start, operation.end, operation.allDay)
    ) {
      announce("Blocked time is unavailable.")
      return
    }

    onEventCreate(operation)
    onSelectedEventChange?.(undefined)
    announce(
      `Created ${operation.title ?? "a new appointment"} for ${formatAnnouncementRange(
        operation.start,
        operation.end,
        operation.allDay
      )}.`
    )
  }

  function requestEventCreate(operation: CalendarCreateOperation) {
    if (
      shouldBlockTimedRange(operation.start, operation.end, operation.allDay)
    ) {
      announce("Blocked time is unavailable.")
      return
    }

    if (onEventCreateRequest) {
      onEventCreateRequest(operation)
      onSelectedEventChange?.(undefined)
      return
    }

    commitCreateEvent(operation)
  }

  function commitMoveEvent(operation: CalendarMoveOperation) {
    if (!onEventMove) {
      return
    }

    const nextOperation = {
      ...operation,
      scope:
        operation.scope ??
        (operation.occurrence.isRecurringInstance ? "series" : "occurrence"),
    } as const

    setOptimisticEvents((currentEvents) =>
      applyMoveOperation(currentEvents, nextOperation)
    )
    onEventMove(nextOperation)
    announce(
      `Moved ${nextOperation.occurrence.title} to ${formatAnnouncementRange(
        nextOperation.nextStart,
        nextOperation.nextEnd,
        nextOperation.allDay ?? nextOperation.occurrence.allDay
      )}.`
    )
  }

  function requestMoveEvent(operation: CalendarMoveOperation) {
    const nextOperation = {
      ...operation,
      scope:
        operation.scope ??
        (operation.occurrence.isRecurringInstance ? "series" : "occurrence"),
    } as const

    if (
      shouldBlockTimedRange(
        nextOperation.nextStart,
        nextOperation.nextEnd,
        nextOperation.allDay ?? nextOperation.occurrence.allDay
      )
    ) {
      announce("Blocked time is unavailable.")
      return
    }

    if (onEventMoveRequest) {
      onEventMoveRequest(nextOperation)
      return
    }

    commitMoveEvent(nextOperation)
  }

  function commitResizeEvent(operation: CalendarResizeOperation) {
    if (!onEventResize) {
      return
    }

    const nextOperation = {
      ...operation,
      scope:
        operation.scope ??
        (operation.occurrence.isRecurringInstance ? "series" : "occurrence"),
    } as const

    setOptimisticEvents((currentEvents) =>
      applyResizeOperation(currentEvents, nextOperation)
    )
    onEventResize(nextOperation)
    announce(
      `Resized ${nextOperation.occurrence.title} to ${formatAnnouncementRange(
        nextOperation.nextStart,
        nextOperation.nextEnd,
        nextOperation.occurrence.allDay
      )}.`
    )
  }

  function requestResizeEvent(operation: CalendarResizeOperation) {
    const nextOperation = {
      ...operation,
      scope:
        operation.scope ??
        (operation.occurrence.isRecurringInstance ? "series" : "occurrence"),
    } as const

    if (
      shouldBlockTimedRange(
        nextOperation.nextStart,
        nextOperation.nextEnd,
        nextOperation.occurrence.allDay
      )
    ) {
      announce("Blocked time is unavailable.")
      return
    }

    if (onEventResizeRequest) {
      onEventResizeRequest(nextOperation)
      return
    }

    commitResizeEvent(nextOperation)
  }

  function moveOccurrenceWithTarget(
    occurrence: CalendarOccurrence,
    target: Parameters<typeof getMoveOperation>[1],
    dragOffsetMinutes = 0
  ) {
    if (
      (!onEventMove && !onEventMoveRequest) ||
      !canMoveOccurrence(occurrence)
    ) {
      return
    }

    requestMoveEvent(
      getMoveOperation(occurrence, target, dragOffsetMinutes, slotDuration)
    )
  }

  function resizeOccurrenceWithTarget(
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    target: Parameters<typeof getResizeOperation>[2]
  ) {
    if (
      (!onEventResize && !onEventResizeRequest) ||
      !canResizeOccurrence(occurrence)
    ) {
      return
    }

    requestResizeEvent(
      getResizeOperation(occurrence, edge, target, slotDuration)
    )
  }

  function handleOpenContextMenu(
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) {
    if (!onEventContextMenu) {
      return
    }

    handleSelectEvent(occurrence)
    onEventContextMenu(occurrence, position)
  }

  function handleEventKeyCommand(
    occurrence: CalendarOccurrence,
    event: React.KeyboardEvent<HTMLButtonElement>
  ) {
    const dayDelta =
      event.key === "ArrowLeft" ? -1 : event.key === "ArrowRight" ? 1 : 0
    const minuteDelta =
      event.key === "ArrowUp"
        ? -slotDuration
        : event.key === "ArrowDown"
          ? slotDuration
          : 0

    if (dayDelta === 0 && minuteDelta === 0) {
      return
    }

    event.preventDefault()

    if (event.shiftKey && (onEventResize || onEventResizeRequest)) {
      if (!canResizeOccurrence(occurrence)) {
        announce("This event cannot be resized.")
        return
      }

      requestResizeEvent({
        occurrence,
        edge: "end",
        nextStart: occurrence.start,
        nextEnd: clampResize(
          addMinutes(addDays(occurrence.end, dayDelta), minuteDelta),
          occurrence.start,
          "end",
          slotDuration
        ),
        previousStart: occurrence.start,
        previousEnd: occurrence.end,
        scope: occurrence.isRecurringInstance ? "series" : "occurrence",
      })
      return
    }

    if (event.altKey && (onEventResize || onEventResizeRequest)) {
      if (!canResizeOccurrence(occurrence)) {
        announce("This event cannot be resized.")
        return
      }

      requestResizeEvent({
        occurrence,
        edge: "start",
        nextStart: clampResize(
          addMinutes(addDays(occurrence.start, dayDelta), minuteDelta),
          occurrence.end,
          "start",
          slotDuration
        ),
        nextEnd: occurrence.end,
        previousStart: occurrence.start,
        previousEnd: occurrence.end,
        scope: occurrence.isRecurringInstance ? "series" : "occurrence",
      })
      return
    }

    if (!onEventMove && !onEventMoveRequest) {
      announce("This event cannot be moved.")
      return
    }

    if (!canMoveOccurrence(occurrence)) {
      announce("This event cannot be moved.")
      return
    }

    requestMoveEvent({
      occurrence,
      nextStart: addMinutes(addDays(occurrence.start, dayDelta), minuteDelta),
      nextEnd: addMinutes(addDays(occurrence.end, dayDelta), minuteDelta),
      previousStart: occurrence.start,
      previousEnd: occurrence.end,
      allDay: occurrence.allDay,
      scope: occurrence.isRecurringInstance ? "series" : "occurrence",
    })
  }

  return {
    announce,
    handleEventKeyCommand,
    handleOpenContextMenu,
    handleSelectEvent,
    liveAnnouncement,
    moveOccurrenceWithTarget,
    requestEventCreate,
    resizeOccurrenceWithTarget,
  }
}

import * as React from "react"

import type {
  CalendarDragData,
  CalendarDropTarget,
  CalendarOccurrence,
} from "../../../types"
import { canMoveOccurrence, canResizeOccurrence } from "../../../utils"

import {
  areDropTargetsEqual,
  dragActivationDistance,
  type DragOverlayPosition,
  getCalendarDropTargetFromPoint,
  getDragOffsetMinutes,
  getDragSurfaceRect,
  getPointerDistance,
  getResizeDropTargetFromPoint,
  isTouchPointer,
  lockDocumentTouchScroll,
  type ActiveDragInteraction,
  type ActiveResizeState,
} from "./root-utils"

type UseCalendarPointerInteractionsOptions = {
  announce: (message: string) => void
  closeContextMenu: () => void
  closeEventDetails: () => void
  enableEventMove: boolean
  enableEventResize: boolean
  moveOccurrenceWithTarget: (
    occurrence: CalendarOccurrence,
    target: CalendarDropTarget,
    dragOffsetMinutes?: number
  ) => void
  resizeOccurrenceWithTarget: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    target: CalendarDropTarget
  ) => void
  preferPragmaticEventMove?: boolean
  selectOccurrence: (occurrence: CalendarOccurrence) => void
}

type ExternalStore<T> = {
  clear: () => void
  getSnapshot: () => T
  setSnapshot: (snapshot: T) => void
  subscribe: (listener: () => void) => () => void
}

function createExternalStore<T>(
  initialSnapshot: T,
  options?: {
    frameThrottle?: boolean
  }
): ExternalStore<T> {
  let snapshot = initialSnapshot
  let queuedSnapshot = initialSnapshot
  let frameId: number | null = null
  const listeners = new Set<() => void>()
  const frameThrottle = options?.frameThrottle ?? false

  function emit() {
    for (const listener of listeners) {
      listener()
    }
  }

  function flush() {
    frameId = null
    snapshot = queuedSnapshot
    emit()
  }

  return {
    clear() {
      queuedSnapshot = initialSnapshot

      if (frameThrottle && frameId != null) {
        cancelAnimationFrame(frameId)
        frameId = null
      }

      if (snapshot !== initialSnapshot) {
        snapshot = initialSnapshot
        emit()
      }
    },
    getSnapshot() {
      return snapshot
    },
    setSnapshot(nextSnapshot) {
      if (!frameThrottle) {
        if (snapshot === nextSnapshot) {
          return
        }

        snapshot = nextSnapshot
        emit()
        return
      }

      queuedSnapshot = nextSnapshot

      if (frameId != null) {
        return
      }

      frameId = requestAnimationFrame(flush)
    },
    subscribe(listener) {
      listeners.add(listener)

      return () => {
        listeners.delete(listener)
      }
    },
  }
}

export function useCalendarPointerInteractions({
  announce,
  closeContextMenu,
  closeEventDetails,
  enableEventMove,
  enableEventResize,
  moveOccurrenceWithTarget,
  preferPragmaticEventMove = false,
  resizeOccurrenceWithTarget,
  selectOccurrence,
}: UseCalendarPointerInteractionsOptions) {
  const [activeDrag, setActiveDrag] = React.useState<CalendarDragData | null>(
    null
  )
  const [activeDropTarget, setActiveDropTarget] =
    React.useState<CalendarDropTarget | null>(null)
  const activeDropTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const lastDropTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const [activeDragOffsetMinutes, setActiveDragOffsetMinutes] =
    React.useState(0)
  const activeDragOffsetMinutesRef = React.useRef(0)
  const [activeDragInteraction, setActiveDragInteraction] =
    React.useState<ActiveDragInteraction | null>(null)
  const activeDragRef = React.useRef<CalendarDragData | null>(null)
  const activeDragInteractionRef = React.useRef<ActiveDragInteraction | null>(
    null
  )
  const [activeResize, setActiveResize] =
    React.useState<ActiveResizeState | null>(null)
  const activeResizeRef = React.useRef<ActiveResizeState | null>(null)
  const [activeResizeTarget, setActiveResizeTarget] =
    React.useState<CalendarDropTarget | null>(null)
  const activeResizeTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const lastResizeTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const [activeDragRect, setActiveDragRect] = React.useState<DOMRect | null>(
    null
  )
  const activeDragRectRef = React.useRef<DOMRect | null>(null)
  const dragOverlayStore = React.useState(() =>
    createExternalStore<DragOverlayPosition | null>(null, {
      frameThrottle: true,
    })
  )[0]
  const activeDropTargetStore = React.useState(() =>
    createExternalStore<CalendarDropTarget | null>(null)
  )[0]
  const suppressedPointerClickOccurrenceIdRef = React.useRef<string | null>(
    null
  )
  const dragTouchScrollReleaseRef = React.useRef<(() => void) | null>(null)
  const resizeTouchScrollReleaseRef = React.useRef<(() => void) | null>(null)

  const updateActiveDrag = React.useCallback(
    (nextDrag: CalendarDragData | null) => {
      activeDragRef.current = nextDrag
      setActiveDrag(nextDrag)
    },
    []
  )

  const updateActiveDragInteraction = React.useCallback(
    (nextInteraction: ActiveDragInteraction | null) => {
      activeDragInteractionRef.current = nextInteraction
      setActiveDragInteraction(nextInteraction)
    },
    []
  )

  const updateActiveResize = React.useCallback(
    (nextResize: ActiveResizeState | null) => {
      activeResizeRef.current = nextResize
      setActiveResize(nextResize)
    },
    []
  )

  const updateActiveDragOffsetMinutes = React.useCallback(
    (nextOffsetMinutes: number) => {
      activeDragOffsetMinutesRef.current = nextOffsetMinutes
      setActiveDragOffsetMinutes(nextOffsetMinutes)
    },
    []
  )

  const updateActiveDragRect = React.useCallback((nextRect: DOMRect | null) => {
    activeDragRectRef.current = nextRect
    setActiveDragRect(nextRect)
  }, [])

  function releaseCapturedPointer(
    captureElement: HTMLElement | null,
    pointerId: number | null | undefined
  ) {
    if (!captureElement || pointerId == null) {
      return
    }

    try {
      if (captureElement.hasPointerCapture(pointerId)) {
        captureElement.releasePointerCapture(pointerId)
      }
    } catch {
      // Ignore capture errors during teardown.
    }
  }

  function releaseTouchScrollLock(
    releaseRef: React.MutableRefObject<(() => void) | null>
  ) {
    releaseRef.current?.()
    releaseRef.current = null
  }

  const updateActiveDropTarget = React.useCallback(
    (target: CalendarDropTarget | null) => {
      if (areDropTargetsEqual(activeDropTargetRef.current, target)) {
        return
      }

      activeDropTargetRef.current = target
      activeDropTargetStore.setSnapshot(target)

      setActiveDropTarget(target)

      if (target) {
        lastDropTargetRef.current = target
      }
    },
    [activeDropTargetStore]
  )

  function updateActiveResizeTarget(target: CalendarDropTarget | null) {
    if (areDropTargetsEqual(activeResizeTargetRef.current, target)) {
      return
    }

    activeResizeTargetRef.current = target
    setActiveResizeTarget(target)

    if (target) {
      lastResizeTargetRef.current = target
    }
  }

  function clearActiveDragState() {
    releaseCapturedPointer(
      activeDragInteractionRef.current?.captureElement ?? null,
      activeDragInteractionRef.current?.pointerId
    )
    releaseTouchScrollLock(dragTouchScrollReleaseRef)
    updateActiveDrag(null)
    updateActiveDragInteraction(null)
    updateActiveDropTarget(null)
    updateActiveDragOffsetMinutes(0)
    updateActiveDragRect(null)
    dragOverlayStore.clear()
    lastDropTargetRef.current = null
  }

  function clearActiveResize() {
    releaseCapturedPointer(
      activeResizeRef.current?.captureElement ?? null,
      activeResizeRef.current?.pointerId
    )
    releaseTouchScrollLock(resizeTouchScrollReleaseRef)
    updateActiveResize(null)
    updateActiveResizeTarget(null)
    lastResizeTargetRef.current = null
  }

  const shouldSuppressEventClick = React.useCallback((occurrenceId: string) => {
    if (suppressedPointerClickOccurrenceIdRef.current !== occurrenceId) {
      return false
    }

    suppressedPointerClickOccurrenceIdRef.current = null
    return true
  }, [])

  const handleResizeHandlePointerDown = React.useCallback(
    (
      occurrence: CalendarOccurrence,
      edge: "start" | "end",
      variant: CalendarDragData["variant"],
      event: React.PointerEvent<HTMLSpanElement>
    ) => {
      if (!enableEventResize || !canResizeOccurrence(occurrence)) {
        announce("This event cannot be resized.")
        return
      }

      closeContextMenu()
      closeEventDetails()
      if (isTouchPointer(event.pointerType)) {
        resizeTouchScrollReleaseRef.current = lockDocumentTouchScroll()
      }

      try {
        event.currentTarget.setPointerCapture(event.pointerId)
      } catch {
        // Pointer capture is not guaranteed on every platform.
      }

      updateActiveResize({
        captureElement: event.currentTarget,
        edge,
        hasPointerCapture: event.currentTarget.hasPointerCapture(
          event.pointerId
        ),
        occurrence,
        pointerId: event.pointerId,
        pointerType: event.pointerType,
        variant,
      })
      updateActiveResizeTarget(
        getResizeDropTargetFromPoint(variant, event.clientX, event.clientY)
      )
    },
    [
      announce,
      closeContextMenu,
      closeEventDetails,
      enableEventResize,
      updateActiveResize,
    ]
  )

  const handleEventDragPointerDown = React.useCallback(
    (
      occurrence: CalendarOccurrence,
      variant: CalendarDragData["variant"],
      event: React.PointerEvent<HTMLButtonElement>
    ) => {
      const selectedDesktopEvent =
        event.pointerType !== "touch" &&
        event.currentTarget.dataset.selected === "true"

      if (
        preferPragmaticEventMove &&
        event.pointerType !== "touch" &&
        !selectedDesktopEvent
      ) {
        return
      }

      if (!enableEventMove || !canMoveOccurrence(occurrence)) {
        return
      }

      closeContextMenu()
      closeEventDetails()
      suppressedPointerClickOccurrenceIdRef.current = null
      if (isTouchPointer(event.pointerType)) {
        event.preventDefault()
        dragTouchScrollReleaseRef.current = lockDocumentTouchScroll()
      }

      try {
        event.currentTarget.setPointerCapture(event.pointerId)
      } catch {
        // Pointer capture is not guaranteed on every platform.
      }

      updateActiveDrag({
        kind: "event",
        occurrence,
        variant,
      })
      updateActiveDragInteraction({
        captureElement: event.currentTarget,
        currentClientX: event.clientX,
        currentClientY: event.clientY,
        hasPointerCapture: event.currentTarget.hasPointerCapture(
          event.pointerId
        ),
        initialClientX: event.clientX,
        initialClientY: event.clientY,
        isDragging: false,
        pointerId: event.pointerId,
        pointerType: event.pointerType,
      })
      updateActiveDropTarget(null)
      lastDropTargetRef.current = null
      updateActiveDragRect(getDragSurfaceRect(event.currentTarget))
      updateActiveDragOffsetMinutes(0)
    },
    [
      closeContextMenu,
      closeEventDetails,
      enableEventMove,
      preferPragmaticEventMove,
      updateActiveDrag,
      updateActiveDropTarget,
      updateActiveDragInteraction,
      updateActiveDragOffsetMinutes,
      updateActiveDragRect,
    ]
  )

  const commitPointerResize = React.useEffectEvent(
    (resize: ActiveResizeState, target: CalendarDropTarget) => {
      resizeOccurrenceWithTarget(resize.occurrence, resize.edge, target)
    }
  )
  const clearPointerResize = React.useEffectEvent(() => {
    clearActiveResize()
  })
  const commitPointerDrag = React.useEffectEvent(
    (
      drag: Extract<CalendarDragData, { kind: "event" }>,
      target: CalendarDropTarget,
      dragOffsetMinutes: number
    ) => {
      moveOccurrenceWithTarget(drag.occurrence, target, dragOffsetMinutes)
    }
  )
  const selectPointerDragOccurrence = React.useEffectEvent(
    (drag: Extract<CalendarDragData, { kind: "event" }>) => {
      selectOccurrence(drag.occurrence)
    }
  )
  const clearPointerDrag = React.useEffectEvent(() => {
    clearActiveDragState()
  })

  React.useLayoutEffect(() => {
    if (!activeResize) {
      return
    }

    const resize = activeResize
    // Resize handles unmount as soon as the preview state replaces the source
    // event, so window-level listeners keep the interaction alive after that.
    const pointerEventTarget = window

    function handlePointerMove(event: Event) {
      if (!(event instanceof PointerEvent)) {
        return
      }

      if (event.pointerId !== resize.pointerId) {
        return
      }

      if (isTouchPointer(resize.pointerType)) {
        event.preventDefault()
      }

      updateActiveResizeTarget(
        getResizeDropTargetFromPoint(
          resize.variant,
          event.clientX,
          event.clientY
        )
      )
    }

    function handlePointerUp(event: Event) {
      if (!(event instanceof PointerEvent)) {
        return
      }

      if (event.pointerId !== resize.pointerId) {
        return
      }

      const target =
        getResizeDropTargetFromPoint(
          resize.variant,
          event.clientX,
          event.clientY
        ) ??
        activeResizeTargetRef.current ??
        lastResizeTargetRef.current

      if (!target) {
        clearPointerResize()
        return
      }

      commitPointerResize(resize, target)
      clearPointerResize()
    }

    function handlePointerCancel(event: Event) {
      if (!(event instanceof PointerEvent)) {
        return
      }

      if (event.pointerId !== resize.pointerId) {
        return
      }

      clearPointerResize()
    }

    pointerEventTarget.addEventListener("pointermove", handlePointerMove, {
      passive: false,
    })
    pointerEventTarget.addEventListener("pointerup", handlePointerUp)
    pointerEventTarget.addEventListener("pointercancel", handlePointerCancel)

    return () => {
      pointerEventTarget.removeEventListener("pointermove", handlePointerMove)
      pointerEventTarget.removeEventListener("pointerup", handlePointerUp)
      pointerEventTarget.removeEventListener(
        "pointercancel",
        handlePointerCancel
      )
    }
  }, [activeResize])

  const activeDragPointerId = activeDragInteraction?.pointerId

  React.useLayoutEffect(() => {
    if (activeDragPointerId == null) {
      return
    }

    const initialInteraction = activeDragInteractionRef.current

    if (
      !initialInteraction ||
      initialInteraction.pointerId !== activeDragPointerId
    ) {
      return
    }

    const pointerId = activeDragPointerId
    const pointerEventTarget =
      initialInteraction.hasPointerCapture && initialInteraction.captureElement
        ? initialInteraction.captureElement
        : window

    function handlePointerMove(event: Event) {
      if (!(event instanceof PointerEvent)) {
        return
      }

      if (event.pointerId !== pointerId) {
        return
      }

      const drag = activeDragRef.current
      const interaction = activeDragInteractionRef.current

      if (!drag || !interaction || drag.kind !== "event") {
        return
      }

      const nextTarget =
        getCalendarDropTargetFromPoint(event.clientX, event.clientY) ??
        lastDropTargetRef.current

      if (!interaction.isDragging) {
        if (
          getPointerDistance(
            interaction.initialClientX,
            interaction.initialClientY,
            event.clientX,
            event.clientY
          ) < dragActivationDistance
        ) {
          return
        }

        if (isTouchPointer(interaction.pointerType)) {
          event.preventDefault()
        }

        updateActiveDragInteraction({
          ...interaction,
          isDragging: true,
        })
        dragOverlayStore.setSnapshot({
          clientX: event.clientX,
          clientY: event.clientY,
        })
        updateActiveDragOffsetMinutes(
          getDragOffsetMinutes(drag, activeDragRectRef.current, event.clientY)
        )
        updateActiveDropTarget(nextTarget)
        return
      }

      if (isTouchPointer(interaction.pointerType)) {
        event.preventDefault()
      }

      dragOverlayStore.setSnapshot({
        clientX: event.clientX,
        clientY: event.clientY,
      })
      updateActiveDropTarget(nextTarget)
    }

    function handlePointerUp(event: Event) {
      if (!(event instanceof PointerEvent)) {
        return
      }

      if (event.pointerId !== pointerId) {
        return
      }

      const drag = activeDragRef.current
      const interaction = activeDragInteractionRef.current

      if (!drag || !interaction || drag.kind !== "event") {
        clearPointerDrag()
        return
      }

      const target =
        getCalendarDropTargetFromPoint(event.clientX, event.clientY) ??
        activeDropTargetRef.current ??
        lastDropTargetRef.current
      const dragOffsetMinutes = activeDragOffsetMinutesRef.current
      const wasDragging = interaction.isDragging

      suppressedPointerClickOccurrenceIdRef.current =
        drag.occurrence.occurrenceId
      clearPointerDrag()

      if (!wasDragging) {
        selectPointerDragOccurrence(drag)
        return
      }

      if (target) {
        commitPointerDrag(drag, target, dragOffsetMinutes)
      }
    }

    function handlePointerCancel(event: Event) {
      if (!(event instanceof PointerEvent)) {
        return
      }

      if (event.pointerId !== pointerId) {
        return
      }

      const drag = activeDragRef.current

      if (drag?.kind === "event") {
        suppressedPointerClickOccurrenceIdRef.current =
          drag.occurrence.occurrenceId
      }

      clearPointerDrag()
    }

    pointerEventTarget.addEventListener("pointermove", handlePointerMove, {
      passive: false,
    })
    pointerEventTarget.addEventListener("pointerup", handlePointerUp)
    pointerEventTarget.addEventListener("pointercancel", handlePointerCancel)

    return () => {
      pointerEventTarget.removeEventListener("pointermove", handlePointerMove)
      pointerEventTarget.removeEventListener("pointerup", handlePointerUp)
      pointerEventTarget.removeEventListener(
        "pointercancel",
        handlePointerCancel
      )
    }
  }, [
    activeDragPointerId,
    dragOverlayStore,
    updateActiveDropTarget,
    updateActiveDragInteraction,
    updateActiveDragOffsetMinutes,
  ])

  return {
    activeDrag,
    activeDragInteraction,
    activeDragOffsetMinutes,
    activeDragRect,
    activeDropTarget,
    activeDropTargetStore,
    activeResize,
    activeResizeTarget,
    dragOverlayStore,
    handleEventDragPointerDown,
    handleResizeHandlePointerDown,
    isPointerDragging:
      activeDrag?.kind === "event" && !!activeDragInteraction?.isDragging,
    shouldSuppressEventClick,
  }
}

import * as React from "react"

import { cn } from "../../lib/utils"

import type {
  CalendarClassNames,
  CalendarEventRenderer,
  CalendarEventVariant,
  CalendarOccurrence,
} from "../../../types"
import {
  formatDurationLabel,
  getAllDayEvents,
  getCalendarSlotClassName,
  getEventMetaLabel,
} from "../../../utils"
import {
  type CalendarEventMenuPosition,
  type TimeGridViewProps,
} from "../../shared"
import { CalendarEventCard, getResolvedAccentColor } from "../event-card"

type AllDayDropZoneProps = {
  classNames?: CalendarClassNames
  day: Date
  density: "comfortable" | "compact"
  dragPreviewOccurrence?: CalendarOccurrence
  draggingOccurrenceId?: string
  events: CalendarOccurrence[]
  getEventColor?: (occurrence: CalendarOccurrence) => string
  hourCycle?: 12 | 24
  isDragTarget: boolean
  interactive: boolean
  locale?: string
  onEventDragPointerDown?: TimeGridViewProps["onEventDragPointerDown"]
  onEventKeyCommand: (
    occurrence: CalendarOccurrence,
    event: React.KeyboardEvent<HTMLButtonElement>
  ) => void
  onOpenContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onSelect: (occurrence: CalendarOccurrence) => void
  pragmaticDragConfigFactory?: (
    occurrence: CalendarOccurrence,
    variant: CalendarEventVariant
  ) => {
    getInitialData: () => {
      occurrence: CalendarOccurrence
      type: "calendar-event"
      variant: CalendarEventVariant
    }
  } | null
  previewOccurrenceId?: string
  renderEvent?: CalendarEventRenderer
  selectedEventId?: string
  shouldSuppressEventClick?: (occurrenceId: string) => boolean
  timeZone?: string
}

export function AllDayDropZone({
  classNames,
  day,
  density,
  dragPreviewOccurrence,
  draggingOccurrenceId,
  events,
  getEventColor,
  hourCycle,
  isDragTarget,
  interactive,
  locale,
  onEventDragPointerDown,
  onEventKeyCommand,
  onOpenContextMenu,
  onSelect,
  pragmaticDragConfigFactory,
  previewOccurrenceId,
  renderEvent,
  selectedEventId,
  shouldSuppressEventClick,
  timeZone,
}: AllDayDropZoneProps) {
  const previewEvents = React.useMemo(
    () =>
      dragPreviewOccurrence
        ? getAllDayEvents([dragPreviewOccurrence], day)
        : [],
    [day, dragPreviewOccurrence]
  )
  const displayEvents = React.useMemo(() => {
    const visibleEvents = events.filter(
      (occurrence) => occurrence.occurrenceId !== draggingOccurrenceId
    )

    if (previewEvents.length === 0) {
      return visibleEvents
    }

    const previewEventIds = new Set(
      previewEvents.map((occurrence) => occurrence.occurrenceId)
    )

    return [
      ...visibleEvents.filter(
        (occurrence) => !previewEventIds.has(occurrence.occurrenceId)
      ),
      ...previewEvents,
    ]
  }, [draggingOccurrenceId, events, previewEvents])

  return (
    <div
      data-calendar-drop-target-day={day.toISOString()}
      data-calendar-drop-target-kind="all-day"
      data-calendar-zoom-day={day.toISOString()}
      data-calendar-zoom-surface="all-day"
      className={getCalendarSlotClassName(
        classNames,
        "allDayLane",
        cn(
          density === "compact"
            ? "min-h-16 border-r border-border/70 px-2 py-1.5 last:border-r-0"
            : "min-h-18 border-r border-border/70 px-2 py-2 last:border-r-0",
          isDragTarget ? "bg-muted/50" : ""
        )
      )}
    >
      <div className="space-y-1">
        {displayEvents.map((occurrence, index) => {
          const isDragPreview = previewEvents.some(
            (previewEvent) =>
              previewEvent.occurrenceId === occurrence.occurrenceId
          )

          return (
            <CalendarEventCard
              key={occurrence.occurrenceId}
              accentColor={getResolvedAccentColor(
                occurrence,
                getEventColor,
                index
              )}
              classNames={classNames}
              density={density}
              dragging={
                isDragPreview
                  ? false
                  : draggingOccurrenceId === occurrence.occurrenceId
              }
              event={occurrence}
              interactive={interactive}
              onDragPointerDown={onEventDragPointerDown}
              onEventKeyCommand={onEventKeyCommand}
              onOpenContextMenu={onOpenContextMenu}
              onSelect={onSelect}
              pragmaticDragConfigFactory={pragmaticDragConfigFactory}
              preview={
                isDragPreview || previewOccurrenceId === occurrence.occurrenceId
              }
              previewMetaLabel={
                density === "compact" &&
                (isDragPreview ||
                  previewOccurrenceId === occurrence.occurrenceId)
                  ? formatDurationLabel(
                      occurrence.start,
                      occurrence.end,
                      occurrence.allDay
                    )
                  : undefined
              }
              renderEvent={renderEvent}
              selected={selectedEventId === occurrence.occurrenceId}
              shouldSuppressClick={shouldSuppressEventClick}
              timeLabel={getEventMetaLabel(occurrence, {
                hourCycle,
                locale,
                timeZone,
              })}
              variant="all-day"
            />
          )
        })}
      </div>
    </div>
  )
}

export const MemoizedAllDayDropZone = React.memo(
  AllDayDropZone,
  (previousProps, nextProps) => {
    return (
      previousProps.classNames === nextProps.classNames &&
      previousProps.day.getTime() === nextProps.day.getTime() &&
      previousProps.density === nextProps.density &&
      previousProps.dragPreviewOccurrence === nextProps.dragPreviewOccurrence &&
      previousProps.draggingOccurrenceId === nextProps.draggingOccurrenceId &&
      previousProps.events === nextProps.events &&
      previousProps.getEventColor === nextProps.getEventColor &&
      previousProps.hourCycle === nextProps.hourCycle &&
      previousProps.isDragTarget === nextProps.isDragTarget &&
      previousProps.interactive === nextProps.interactive &&
      previousProps.locale === nextProps.locale &&
      previousProps.onEventDragPointerDown ===
        nextProps.onEventDragPointerDown &&
      previousProps.onEventKeyCommand === nextProps.onEventKeyCommand &&
      previousProps.onOpenContextMenu === nextProps.onOpenContextMenu &&
      previousProps.onSelect === nextProps.onSelect &&
      previousProps.pragmaticDragConfigFactory ===
        nextProps.pragmaticDragConfigFactory &&
      previousProps.previewOccurrenceId === nextProps.previewOccurrenceId &&
      previousProps.renderEvent === nextProps.renderEvent &&
      previousProps.selectedEventId === nextProps.selectedEventId &&
      previousProps.shouldSuppressEventClick ===
        nextProps.shouldSuppressEventClick &&
      previousProps.timeZone === nextProps.timeZone
    )
  }
)

import type { TimeGridViewProps } from "../../shared"
import {
  getBlockedSegmentsForDay,
  getBusinessHourSegmentsForDay,
  getOutsideBusinessHourSegmentsForDay,
} from "../../../utils"

type TimeGridBackgroundProps = {
  blockedRanges: TimeGridViewProps["blockedRanges"]
  businessHours: TimeGridViewProps["businessHours"]
  day: Date
  gridHeight: number
  maxMinute: number
  minMinute: number
  slotDuration: number
  slotHeight: number
}

export function TimeGridBackground({
  blockedRanges,
  businessHours,
  day,
  gridHeight,
  maxMinute,
  minMinute,
  slotDuration,
  slotHeight,
}: TimeGridBackgroundProps) {
  const outsideBusinessHourSegments = getOutsideBusinessHourSegmentsForDay(
    day,
    businessHours,
    minMinute,
    maxMinute
  )
  const businessHourSegments = getBusinessHourSegmentsForDay(
    day,
    businessHours,
    minMinute,
    maxMinute
  )
  const blockedSegments = getBlockedSegmentsForDay(
    day,
    blockedRanges,
    minMinute,
    maxMinute
  )

  return (
    <div className="pointer-events-none absolute inset-0">
      {outsideBusinessHourSegments.map((segment) => (
        <div
          key={`outside-${segment.startMinute}-${segment.endMinute}`}
          className="absolute inset-x-0 bg-muted/20"
          style={{
            height:
